concept_explanation.mocking_http_client:
**Mocking HttpClient for API client tests:**

```java
import java.net.http.*;
import org.mockito.*;

@ExtendWith(MockitoExtension.class)
class StockApiClientTest {
    @Mock HttpClient httpClient;
    @Mock HttpResponse<String> httpResponse;
    @InjectMocks StockApiClient apiClient;  // or inject manually

    @Test
    void fetchPrice_validSymbol_returnsPrice() throws Exception {
        // Stub the response:
        String responseBody = "{\"symbol\":\"TCS\",\"price\":3890}";
        when(httpResponse.statusCode()).thenReturn(200);
        when(httpResponse.body()).thenReturn(responseBody);
        when(httpClient.send(any(HttpRequest.class), any()))
            .thenReturn(httpResponse);

        // Call the API client:
        StockQuote quote = apiClient.fetchPrice("TCS");

        // Assert:
        assertEquals("TCS", quote.symbol());
        assertEquals(3890,   quote.price());
    }

    @Test
    void fetchPrice_serverError_returnsEmpty() throws Exception {
        when(httpResponse.statusCode()).thenReturn(500);
        when(httpResponse.body()).thenReturn("Internal Server Error");
        when(httpClient.send(any(), any())).thenReturn(httpResponse);

        assertTrue(apiClient.fetchPrice("TCS").isEmpty());
    }

    @Test
    void fetchPrice_networkError_throwsIOException() throws Exception {
        when(httpClient.send(any(), any()))
            .thenThrow(new IOException("Connection refused"));

        assertThrows(IOException.class, () -> apiClient.fetchPrice("TCS"));
    }
}
```

