step_by_step_solution.details:
```java
record Product(String sku, String name, int qty, double price) {}

class InventoryReportService {
    List<Product> readProducts(Path csvPath) throws IOException {
        return Files.readAllLines(csvPath).stream()
            .skip(1)  // skip header
            .filter(line -> !line.isBlank())
            .map(line -> {
                try {
                    String[] cols = line.split(",");
                    return new Product(cols[0].trim(), cols[1].trim(),
                        Integer.parseInt(cols[2].trim()),
                        Double.parseDouble(cols[3].trim()));
                } catch (Exception e) { return null; }  // skip bad rows
            })
            .filter(Objects::nonNull)
            .collect(Collectors.toList());
    }

    void writeReport(List<Product> products, Path reportPath) throws IOException {
        List<String> lines = new ArrayList<>();
        lines.add("=== Inventory Report ===");
        lines.add("Items: " + products.size());
        products.forEach(p -> lines.add(
            String.format("%s | %s | qty:%d | ₹%.2f", p.sku(), p.name(), p.qty(), p.price())));
        Files.write(reportPath, lines);
    }
}
```

