import org.junit.jupiter.api.*;
import org.junit.jupiter.api.io.TempDir;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;
import static org.junit.jupiter.api.Assertions.*;

class InventoryReportServiceTest {
    InventoryReportService service = new InventoryReportService();

    @Test
    void readProducts_validCsv_returns3Products(@TempDir Path tempDir) throws Exception {
        Path csv = tempDir.resolve("inventory.csv");
        Files.writeString(csv, "sku,name,qty,price\nP001,Mouse,50,799.0\nP002,Keyboard,12,1999.0\nP003,Hub,60,499.0");
        List<Product> p = service.readProducts(csv);
        assertEquals(3, p.size());
        assertEquals("P001", p.get(0).sku());
    }

    @Test
    void readProducts_emptyFile_returnsEmptyList(@TempDir Path tempDir) throws Exception {
        Path csv = tempDir.resolve("empty.csv");
        Files.writeString(csv, "sku,name,qty,price\n");  // header only
        assertTrue(service.readProducts(csv).isEmpty());
    }

    @Test
    void readProducts_malformedRow_skipsAndContinues(@TempDir Path tempDir) throws Exception {
        Path csv = tempDir.resolve("mixed.csv");
        Files.writeString(csv, "sku,name,qty,price\nP001,Mouse,50,799.0\nBAD_ROW\nP002,Keyboard,12,1999.0");
        List<Product> p = service.readProducts(csv);
        assertEquals(2, p.size());
    }

    @Test
    void readProducts_nonExistentFile_throwsNoSuchFileException(@TempDir Path tempDir) {
        Path missing = tempDir.resolve("missing.csv");
        assertThrows(NoSuchFileException.class, () -> service.readProducts(missing));
    }

    @Test
    void writeReport_3products_correctContent(@TempDir Path tempDir) throws Exception {
        List<Product> products = List.of(
            new Product("P001", "Mouse", 50, 799.0),
            new Product("P002", "Keyboard", 12, 1999.0),
            new Product("P003", "Hub", 60, 499.0));
        Path report = tempDir.resolve("report.txt");
        service.writeReport(products, report);
        List<String> lines = Files.readAllLines(report);
        assertEquals(5, lines.size());
        assertEquals("=== Inventory Report ===", lines.get(0));
        assertEquals("Items: 3", lines.get(1));
        assertTrue(lines.get(2).contains("P001"));
        assertTrue(lines.get(4).contains("Hub"));
    }

    @Test
    void fullPipeline_readThenWrite_roundTrip(@TempDir Path tempDir) throws Exception {
        Path csv = tempDir.resolve("input.csv");
        Files.writeString(csv, "sku,name,qty,price\nP001,Mouse,50,799.0");
        Path report = tempDir.resolve("report.txt");
        List<Product> products = service.readProducts(csv);
        service.writeReport(products, report);
        String reportContent = Files.readString(report);
        assertTrue(reportContent.contains("P001"));
        assertTrue(reportContent.contains("Mouse"));
    }
}

